import type { NextApiRequest, NextApiResponse } from 'next';

interface $RESPONSEData {
	$FIELD_NAME: $FIELD_TYPE;
}

interface ErrorResponse {
	error: string;
}

export default async function handler(
	req: NextApiRequest,
	res: NextApiResponse<$RESPONSEData | ErrorResponse>
): Promise<void> {
	if (req.method === 'GET') {
		try {
			$GET_LOGIC
			res.status(200).json({ $FIELD_NAME: $RESPONSE_VALUE });
		} catch (error) {
			res.status(500).json({ error: 'Internal Server Error' });
		}
	} else if (req.method === 'POST') {
		try {
			const body = req.body as $REQUEST_TYPE;
			$POST_LOGIC
			res.status(201).json({ $FIELD_NAME: $RESPONSE_VALUE });
		} catch (error) {
			res.status(500).json({ error: 'Internal Server Error' });
		}
	} else {
		res.setHeader('Allow', ['GET', 'POST']);
		res.status(405).json({ error: `Method ${req.method} Not Allowed` });
	}
}

import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest): NextResponse {
	const { pathname } = request.nextUrl;

	if (pathname.startsWith('$PROTECTED_PATH')) {
		const token = request.cookies.get('$AUTH_COOKIE')?.value;

		if (!token) {
			return NextResponse.redirect(new URL('$REDIRECT_PATH', request.url));
		}
	}

	$MIDDLEWARE_LOGIC

	return NextResponse.next();
}

