interface $NAMEPageProps {
	params: { $PARAM_NAME: string };
	searchParams: { [key: string]: string | string[] | undefined };
}

async function getData($PARAM_NAME: string): Promise<$DATA_TYPE> {
	const res = await fetch(`$API_URL/${$PARAM_NAME}`, {
		cache: '$CACHE_STRATEGY',
		next: { revalidate: $REVALIDATE_SECONDS },
	});

	if (!res.ok) {
		throw new Error('Failed to fetch data');
	}

	return res.json() as Promise<$DATA_TYPE>;
}

export default async function $NAMEPage({
	params,
}: $NAMEPageProps): Promise<JSX.Element> {
	const data = await getData(params.$PARAM_NAME);

	return (
		<main>
			{$CONTENT}
		</main>
	);
}

