'use server';

import { revalidatePath } from 'next/cache';
import { redirect } from 'next/navigation';

interface $ACTION_NAMEInput {
	$FIELD_NAME: $FIELD_TYPE;
}

interface $ACTION_NAMEResult {
	success: boolean;
	error?: string;
	data?: $DATA_TYPE;
}

export async function $ACTION_NAME(
	prevState: $ACTION_NAMEResult | null,
	formData: FormData
): Promise<$ACTION_NAMEResult> {
	try {
		const $FIELD_NAME = formData.get('$FIELD_NAME') as string;

		$ACTION_LOGIC

		revalidatePath('$REVALIDATE_PATH');
		return { success: true, data: $RESULT_DATA };
	} catch (error) {
		return {
			success: false,
			error: error instanceof Error ? error.message : 'An error occurred',
		};
	}
}

import { NextRequest, NextResponse } from 'next/server';

interface $RESPONSEData {
	$FIELD_NAME: $FIELD_TYPE;
}

export async function GET(
	request: NextRequest,
	{ params }: { params: { $PARAM_NAME: string } }
): Promise<NextResponse<$RESPONSEData>> {
	try {
		const { searchParams } = new URL(request.url);
		const $QUERY_PARAM = searchParams.get('$QUERY_NAME');

		$GET_LOGIC

		return NextResponse.json({ $FIELD_NAME: $RESPONSE_VALUE });
	} catch (error) {
		return NextResponse.json(
			{ error: 'Internal Server Error' },
			{ status: 500 }
		);
	}
}

export async function POST(
	request: NextRequest
): Promise<NextResponse<$RESPONSEData>> {
	try {
		const body = await request.json() as $REQUEST_TYPE;

		$POST_LOGIC

		return NextResponse.json(
			{ $FIELD_NAME: $RESPONSE_VALUE },
			{ status: 201 }
		);
	} catch (error) {
		return NextResponse.json(
			{ error: 'Internal Server Error' },
			{ status: 500 }
		);
	}
}

import type { Metadata, ResolvingMetadata } from 'next';

interface Props {
	params: { $PARAM_NAME: string };
	searchParams: { [key: string]: string | string[] | undefined };
}

export async function generateMetadata(
	{ params, searchParams }: Props,
	parent: ResolvingMetadata
): Promise<Metadata> {
	const $DATA = await fetch(`$API_URL/${params.$PARAM_NAME}`).then(
		(res) => res.json() as Promise<$DATA_TYPE>
	);

	return {
		title: $DATA.$TITLE_FIELD,
		description: $DATA.$DESCRIPTION_FIELD,
		openGraph: {
			images: [$DATA.$IMAGE_FIELD],
		},
	};
}
